bool isBalanced(String s) {
  final stack = <String>[];
  final pairs = {')': '(', '}': '{', ']': '['};

  for (var char in s.split('')) {
    if ('({['.contains(char)) {
      stack.add(char);
    } else if (')}]'.contains(char)) {
      if (stack.isEmpty || stack.last != pairs[char]) {
        return false;
      }
      stack.removeLast();
    }
  }

  return stack.isEmpty;
}

// Usage
print(isBalanced('({[]})')); // true
print(isBalanced('({[}])'));  // false
print(isBalanced('((())'));   // false
```

**Time Complexity**: O(n)
**Space Complexity**: O(n)

